mapper.select:
SELECT s.id, s.merchant_id, s.category_id, c.name AS category_name, s.name, s.price, s.image, s.description, s.status, s.create_time, s.update_time FROM setmeal s LEFT JOIN category c ON s.category_id = c.id WHERE s.merchant_id = #{query.merchantId}
AND s.name LIKE CONCAT('%', #{query.name}, '%')
AND s.category_id = #{query.categoryId}
AND s.status = #{query.status}
ORDER BY s.create_time DESC
